const DAYS_ORDER_CSV = ['Понедельник','Вторник','Среда','Четверг','Пятница','Суббота'];

function parseCellText(text) {
  if (!text || !text.trim()) return null;
  text = text.trim();
  const typeMap = {'л.':'лек','пр.':'пр','лаб.':'лаб','КРП':'лек','КОП':'лек'};
  let ptype = 'лек';
  for (const [prefix, t] of Object.entries(typeMap)) {
    if (text.startsWith(prefix)) { text = text.slice(prefix.length).trim(); ptype = t; break; }
  }
  const lines = text.split('\n');
  const main = lines[0].trim();
  const note = lines.slice(1).map(l => l.trim()).filter(Boolean).join(' ');
  const roomMatch = main.match(/(\d+\s*[А-ЯA-Z]?\s*\/\S+)/);
  let room = '', beforeRoom = main;
  if (roomMatch) { room = roomMatch[1].trim(); beforeRoom = main.slice(0, roomMatch.index).trim(); }
  const teacherMatch = beforeRoom.match(/(доц\.|пр\.|ст\.пр\.|зав\.каф\.|проф\.)/);
  let teacher = '', subject = beforeRoom;
  if (teacherMatch) { subject = beforeRoom.slice(0, teacherMatch.index).trim(); teacher = beforeRoom.slice(teacherMatch.index).trim(); }
  return { subject: subject.trim(), teacher: teacher.trim(), room: room.trim(), note: note.trim(), type: ptype };
}

function parseCSV(csvText) {
  // Split rows, handle quoted fields
  const rows = [];
  const lines = csvText.split(/\r?\n/);
  for (const line of lines) {
    const row = [];
    let cur = '', inQ = false;
    for (let i = 0; i < line.length; i++) {
      const c = line[i];
      if (c === '"') { inQ = !inQ; }
      else if (c === ',' && !inQ) { row.push(cur); cur = ''; }
      else { cur += c; }
    }
    row.push(cur);
    rows.push(row.map(v => v.replace(/\\n/g, '\n').replace(/\r/g, '').trim()));
  }
  if (rows.length < 2) return null;

  const headerRow = rows[0];
  const groups = [];
  const groupCols = {};
  for (let i = 4; i < headerRow.length; i++) {
    const h = headerRow[i];
    if (h && (h.includes('ИИЭСМ') || h.includes(' so '))) {
      groups.push(h);
      groupCols[h] = i;
    }
  }
  if (!groups.length) return null;

  const schedule = {};
  groups.forEach(g => schedule[g] = {});
  let currentDay = null, currentPara = null, currentTime = null;

  for (let ri = 1; ri < rows.length; ri++) {
    const row = rows[ri];
    const col0 = row[0] || '', col2 = row[2] || '', col3 = row[3] || '';
    if (DAY_MAP_CSV[col0.trim()]) currentDay = DAY_MAP_CSV[col0.trim()];
    const paraNum = parseInt(col2);
    if (!isNaN(paraNum) && paraNum >= 1 && paraNum <= 6) {
      currentPara = paraNum;
      currentTime = TIME_MAP_CSV[paraNum] || '';
    }
    if (!currentDay || !currentPara) continue;
    const isOdd = col3.includes('Нечетная');
    const isEven = col3.includes('Четная');
    if (!isOdd && !isEven) continue;
    const wk = isOdd ? 'odd' : 'even';

    for (const g of groups) {
      const ci = groupCols[g];
      const cellVal = row[ci] || '';
      if (!cellVal.trim()) continue;
      const parsed = parseCellText(cellVal);
      if (!parsed) continue;
      if (!schedule[g][currentDay]) schedule[g][currentDay] = {};
      const pk = String(currentPara);
      if (!schedule[g][currentDay][pk]) schedule[g][currentDay][pk] = { para: currentPara, time: currentTime, odd: [], even: [] };
      schedule[g][currentDay][pk][wk].push(parsed);
    }
  }

  const resultSchedule = {};
  for (const g of groups) {
    resultSchedule[g] = {};
    for (const day of DAYS_ORDER_CSV) {
      if (schedule[g][day]) {
        resultSchedule[g][day] = Object.values(schedule[g][day]).sort((a,b) => a.para - b.para);
      }
    }
  }

  return {
    groups: groups.map(g => {
      const parts = g.split(' ');
      return { id: g, num: parts[1] || g, dept: g.includes('_') ? g.split('_')[1] : '' };
    }),
    schedule: resultSchedule,
    days: DAYS_ORDER_CSV
  };
}


let D = FALLBACK_DATA; 

async function loadScheduleFromSheets() {
  if (!SHEETS_CSV_URL) return; // URL не настроен — используем встроенные данные
  try {
    // Добавляем cache-bust чтобы не кэшировало старую версию
    const url = SHEETS_CSV_URL + (SHEETS_CSV_URL.includes('?') ? '&' : '?') + '_t=' + Date.now();
    const resp = await fetch(url);
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    const csv = await resp.text();
    const parsed = parseCSV(csv);
    if (parsed && parsed.groups.length > 0) {
      D = parsed;
      // Обновляем UI если страница уже загружена
      if (typeof window !== 'undefined' && window._scheduleLoaded) {
        window._scheduleLoaded();
      }
      console.log('✅ Расписание загружено из Google Sheets (' + parsed.groups.length + ' групп)');
    }
  } catch (e) {
    console.warn('⚠️ Не удалось загрузить из Google Sheets, используются встроенные данные:', e.message);
  }
}

// Запускаем загрузку (неблокирующая)
if (typeof window !== 'undefined') {
  loadScheduleFromSheets();
}
